using System.ComponentModel;
using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

internal class MyPropertyEditor : UITypeEditor
{
    public override object? EditValue(ITypeDescriptorContext? context, IServiceProvider provider, object? value)
    {
        var editorService = provider?.GetService(typeof(IWindowsFormsEditorService)) as IWindowsFormsEditorService;
        if (editorService is null)
            return value;

        var control = CreateDropDownControl(value);

        // .NET 9: DropDownControl throws ArgumentNullException when passed null
        if (control is not null)
        {
            editorService.DropDownControl(control);
            value = (control as ListBox)?.SelectedItem;
        }

        return value;
    }

    private static Control? CreateDropDownControl(object? currentValue)
    {
        if (currentValue is not string text || string.IsNullOrEmpty(text))
            return null;

        var listBox = new ListBox();
        listBox.Items.Add(text);
        return listBox;
    }

    public override UITypeEditorEditStyle GetEditStyle(ITypeDescriptorContext? context)
        => UITypeEditorEditStyle.DropDown;
}

